// BuildOrFilter builds a filter with $or logic from multiple filter groups
func BuildOrFilter(filterGroups []map[string]interface{}) bson.D {
	orConditions := bson.A{}
	for _, group := range filterGroups {
		condition := bson.D{}
		for key, value := range group {
			condition = append(condition, bson.E{Key: key, Value: value})
		}
		orConditions = append(orConditions, condition)
	}
	return bson.D{{Key: "$or", Value: orConditions}}
}

