// executeQuery is the internal method that executes the query with given filter and options
func (mqb *MongoQueryBuilder) executeQuery(ctx context.Context, filter bson.D, opts *QueryOptions) ([]QueryResult, error) {
	collection := mqb.client.Database(mqb.database).Collection(mqb.collection)

	findOpts := options.Find()
	if opts != nil {
		if opts.Limit > 0 {
			findOpts.SetLimit(opts.Limit)
		}
		if opts.Skip > 0 {
			findOpts.SetSkip(opts.Skip)
		}
		if opts.SortField != "" {
			findOpts.SetSort(bson.D{{Key: opts.SortField, Value: opts.SortOrder}})
		}
	}

	cursor, err := collection.Find(ctx, filter, findOpts)
	if err != nil {
		return nil, fmt.Errorf("failed to execute query: %w", err)
	}
	defer cursor.Close(ctx)

	var results []QueryResult
	for cursor.Next(ctx) {
		var result QueryResult
		if err := cursor.Decode(&result); err != nil {
			return nil, fmt.Errorf("failed to decode document: %w", err)
		}
		results = append(results, result)
	}

	if err := cursor.Err(); err != nil {
		return nil, fmt.Errorf("cursor error: %w", err)
	}

	return results, nil
}

